        // Check if all nodes are connected
        for (let i = 1; i < n; i++) {
            if (uf.find(i) !== uf.find(0)) {
                low = mid + 1;
                break;
            }
        } else {
            answer = mid;
            high = mid - 1;
        }
    }

    return answer;
